use vstd::prelude::*;

verus! {
    // Following is the block for necessary definitions
    // <preamble>
    spec fn is_sorted(s: Seq<i32>) -> bool {
        forall|i: int, j: int| 0 <= i < j < s.len() ==> s[i] <= s[j]
    }

    spec fn is_valid_index_permutation(p: Seq<int>, n: int) -> bool {
        p.len() == n
        && (forall|i: int| 0 <= i < n ==> 0 <= #[trigger] p[i] < n)
        && (forall|i: int, j: int| 0 <= i < j < n ==> #[trigger] p[i] != #[trigger] p[j])
    }

    spec fn is_permutation(v1: Seq<i32>, v2: Seq<i32>) -> bool {
        exists|p: Seq<int>| 
            is_valid_index_permutation(p, v1.len() as int) 
            && v1.len() == v2.len()
            && (forall|i: int| 0 <= i < v1.len() ==> v2[i] == v1[#[trigger] p[i]])
    }
    // </preamble>

    // Following is the block for potential helper specifications
    // <helpers>

    // </helpers>

    // Following is the block for proofs of lemmas, or functions that help the implementation or verification of the main specification
    // <proofs>
    proof fn lemma_swap_permutation(v1: Seq<i32>, v2: Seq<i32>, i: int, j: int)
        requires
            0 <= i < v2.len(),
            0 <= j < v2.len(),
            v1.len() == v2.len(),
            is_permutation(v1, v2),
        ensures
            is_permutation(v1, v2.update(i, v2[j]).update(j, v2[i])),
    {
        let v3 = v2.update(i, v2[j]).update(j, v2[i]);
        let n = v1.len() as int;

        // Instantiate the existential quantifier from the precondition
        let p = choose|p: Seq<int>| is_valid_index_permutation(p, n) 
                && v1.len() == v2.len()
                && (forall|k: int| 0 <= k < n ==> v2[k] == v1[p[k]]);

        // Construct the new permutation map p'
        // If v2[k] mapped to v1[p[k]], and we swap indices i and j in v2 to get v3,
        // then v3[i] == v2[j] == v1[p[j]], so p'[i] must be p[j].
        let p_prime = Seq::new(n as nat, |k: int| 
            if k == i { p[j] }
            else if k == j { p[i] }
            else { p[k] }
        );

        // Prove p_prime properties
        assert(p_prime.len() == n);
        assert(forall|k: int| 0 <= k < n ==> 0 <= p_prime[k] < n);

        // Prove distinctness of p_prime
        assert(forall|a: int, b: int| 0 <= a < b < n ==> p_prime[a] != p_prime[b]) by {
            // Case analysis handles the swap logic for distinctness automatically with the definition
            if a == i {
                if b == j {
                    // p_prime[a] is p[j], p_prime[b] is p[i]. p[j] != p[i] since i != j (if distinct) or trivial.
                }
            }
        };

        assert(is_valid_index_permutation(p_prime, n));

        // Prove the value mapping
        assert(forall|k: int| 0 <= k < n ==> v3[k] == v1[p_prime[k]]);
    }

    // Lemma to glue the two sorted parts after the inner loop finishes
    proof fn lemma_sorted_extension(v: Seq<i32>, j: int, end: int)
        requires
            0 <= j < end <= v.len(),
            // Prefix 0..j is sorted
            is_sorted(v.subrange(0, j)),
            // Suffix j..end is sorted
            is_sorted(v.subrange(j, end)),
            // Everything in prefix (excluding j) is smaller than everything in suffix (excluding j)
            // Note: In the loop invariant, 'j' is the hole.
            // The invariant passed here guarantees v[0..j] <= v[j+1..end].
            forall|a: int, b: int| 0 <= a < j && j < b < end ==> v[a] <= v[b],
            // Stop condition or boundary
            j > 0 ==> v[j-1] <= v[j],
        ensures
            is_sorted(v.subrange(0, end)),
    {
        let s = v.subrange(0, end);
        // We need to prove forall indices x, y in 0..end, s[x] <= s[y]
        assert forall|x: int, y: int| 0 <= x < y < end ==> s[x] <= s[y] by {
            if x < j {
                if y < j {
                    // Both in prefix, handled by is_sorted(0..j)
                } else { // y >= j
                    if y > j {
                        // Split across hole, handled by forall assumption
                    } else { // y == j
                         // We need v[x] <= v[j] where x < j.
                         // Since x is int, x <= j-1.
                         // From is_sorted(0..j), v[x] <= v[j-1].
                         // From assumption, v[j-1] <= v[j].
                         // Transitivity holds.
                    }
                }
            } else {
                // Both in suffix (>= j), handled by is_sorted(j..end)
            }
        };
    }
    // </proofs>

    // Following is the block for the main specification
    // <spec>
    fn insertion_sort(v: &mut Vec<i32>)
        ensures
            is_sorted(v@),
            is_permutation(old(v)@, v@),
    // </spec>
    // <code>
    {
        let n = v.len();
        if n == 0 {
            return;
        }

        // Outer loop: Invariant is that the prefix 0..i is sorted
        for i in 1..n
            invariant
                n == v.len(),
                0 <= i <= n,
                is_sorted(v@.subrange(0, i as int)),
                is_permutation(old(v)@, v@),
        {
            let mut j = i;
            // Inner loop: shifts v[j] left into correct position
            while j > 0 && v[j-1] > v[j]
                invariant
                    n == v.len(),
                    0 <= j <= i < n,
                    is_permutation(old(v)@, v@),
                    // The array is sorted except possibly at index j relative to j-1
                    is_sorted(v@.subrange(0, j as int)),
                    is_sorted(v@.subrange(j as int, (i + 1) as int)),
                    // Partition property: left part (0..j) <= right part (j+1..i+1)
                    forall|a: int, b: int| 0 <= a < j && j < b <= i ==> v[a] <= v[b],
            {
                let ghost v_prev = v@;

                // Swap v[j] and v[j-1]
                let temp = v[j];
                v.set(j, v[j-1]);
                v.set(j-1, temp);

                // Prove permutation is preserved
                lemma_swap_permutation(old(v)@, v_prev, (j-1) as int, j as int);

                j = j - 1;
            }
            // Use lemma to show that the loop termination condition implies the whole range 0..i+1 is sorted
            lemma_sorted_extension(v@, j as int, (i + 1) as int);
        }
    }
    // </code>

    #[verifier::external]
    fn main() {
        let mut v = vec![5, 1, 4, 2, 8];
        let ghost original_v = v@;

        insertion_sort(&mut v);

        assert(is_sorted(v@));
        assert(is_permutation(original_v, v@));
    }
}
